      options: [{ id: `A`, text: `It illustrates the importance of an organization mentioned in the text.` }, { id: `B`, text: `It compares the achievements of two people discussed later in the text.` }, { id: `C`, text: `It argues against the claim made earlier in the text.` }, { id: `D`, text: `It provides additional information about a person discussed in the text.` }],
